package ir.tahamohamadi.blog.post; import jakarta.persistence.*; import lombok.*; import java.io.Serializable; import java.util.*;
@Embeddable @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class BlogPostMediaId implements Serializable { @Column(name="blog_post_id") private UUID blogPostId; @Column(name="media_asset_id") private UUID mediaAssetId; @Enumerated(EnumType.STRING) @Column(name="usage") private BlogPostMediaUsage usage; public BlogPostMediaId(UUID post,UUID media,BlogPostMediaUsage usage){blogPostId=Objects.requireNonNull(post);mediaAssetId=Objects.requireNonNull(media);this.usage=Objects.requireNonNull(usage);} @Override public boolean equals(Object o){return this==o||(o instanceof BlogPostMediaId i&&blogPostId.equals(i.blogPostId)&&mediaAssetId.equals(i.mediaAssetId)&&usage==i.usage);} @Override public int hashCode(){return Objects.hash(blogPostId,mediaAssetId,usage);} }
